/**
 * lab/db.js
 * ─────────────────────────────────────────────────────────────────────
 * All Firestore reads and writes for the Knowledge Extraction Lab.
 *
 * Collection: `sessions`
 * Document ID: auto-generated by Firestore, backfilled into sessionId field
 *
 * IMPORTANT: Replace 10.14.1 with the Firebase SDK version your repo
 * already uses. Check the import URL inside firebase.js at the repo root.
 */

import { db } from '../firebase.js';
import {
    collection,
    doc,
    addDoc,
    getDoc,
    updateDoc,
    getDocs,
    query,
    where,
    orderBy,
    limit,
    serverTimestamp,
} from 'https://www.gstatic.com/firebasejs/10.12.0/firebase-firestore.js';

const SESSIONS = 'sessions';

// ── Create ────────────────────────────────────────────────────────────

/**
 * Creates a new session document in Firestore.
 * All fields are initialised to their empty/null states so the document
 * shape is always complete, even before individual screens fill them in.
 *
 * @param  {string} expertUid  — Firebase auth UID of the signed-in expert
 * @returns {Promise<string>}  — the new Firestore document ID (sessionId)
 */
export async function createSession(expertUid) {
    const docRef = await addDoc(collection(db, SESSIONS), {
        sessionId: null,          // backfilled below
        createdAt: serverTimestamp(),
        expertUid,

        // Stage 0 — Foundation
        profile: null,
        cueLibrary: [],
        decisionOptions: [],

        // Stage 1 — Sorting Task
        sortingTask: null,

        // Stage 2 — Scenario Session
        scenarios: [],

        // Stage 3 — Policy Model
        policyModel: null,

        // Stage 4 — Elicitation
        elicitation: null,

        // Stage 5 — Recipe
        recipe: null,

        // Stage 6 — Transfer
        transfer: null,
    });

    // Backfill sessionId so it mirrors the Firestore document ID
    await updateDoc(docRef, { sessionId: docRef.id });

    return docRef.id;
}

// ── Read ──────────────────────────────────────────────────────────────

/**
 * Retrieves a full session document by its ID.
 *
 * @param  {string} sessionId
 * @returns {Promise<object|null>}  — session data object, or null if not found
 */
export async function getSession(sessionId) {
    const snap = await getDoc(doc(db, SESSIONS, sessionId));
    return snap.exists() ? snap.data() : null;
}

/**
 * Retrieves the most recently created session for a given expert.
 * Used to resume an in-progress session after sign-in.
 *
 * @param  {string} expertUid
 * @returns {Promise<object|null>}  — most recent session data, or null
 */
export async function getLatestSession(expertUid) {
    const q = query(
        collection(db, SESSIONS),
        where('expertUid', '==', expertUid),
        orderBy('createdAt', 'desc'),
        limit(1)
    );
    const snap = await getDocs(q);
    if (snap.empty) return null;
    return snap.docs[0].data();
}

// ── Update — Stage 0: Foundation ─────────────────────────────────────

/**
 * Saves the expert profile fields into the session document.
 *
 * @param {string} sessionId
 * @param {{ role: string, whatYouDo: string, decisionTypes: string,
 *            whatMakesItHard: string, documentsText: string }} profile
 */
export async function updateProfile(sessionId, profile) {
    await updateDoc(doc(db, SESSIONS, sessionId), { profile });
}

/**
 * Saves the full cue library array (after extraction or expert editing).
 * This replaces the entire array — do not use for partial updates.
 *
 * Each cue: { id, name, definition, scale, layer, options }
 *
 * @param {string} sessionId
 * @param {Array}  cueLibrary
 */
export async function updateCueLibrary(sessionId, cueLibrary) {
    await updateDoc(doc(db, SESSIONS, sessionId), { cueLibrary });
}

/**
 * Saves the confirmed decision option set for this session.
 * Locked after Screen 4 — not modified after that.
 *
 * Each option: { id: string, label: string, description: string }
 *
 * @param {string} sessionId
 * @param {Array}  decisionOptions
 */
export async function updateDecisionOptions(sessionId, decisionOptions) {
    await updateDoc(doc(db, SESSIONS, sessionId), { decisionOptions });
}

// ── Update — Stage 1: Sorting Task ───────────────────────────────────

/**
 * Saves the sorting task data: the 12 generated situations and the
 * expert's grouping with discrimination notes.
 *
 * @param {string} sessionId
 * @param {{
 *   situations: string[],
 *   groups: Array<{ situationIds: string[], commonality: string, discriminator: string }>
 * }} sortingTask
 */
export async function updateSortingTask(sessionId, sortingTask) {
    await updateDoc(doc(db, SESSIONS, sessionId), { sortingTask });
}

// ── Update — Stage 2: Scenario Session ───────────────────────────────

/**
 * Saves all 30 scenario records for a session (full replace).
 * Called once after the complete session is done, not after each scenario.
 *
 * Each scenario: {
 *   scenarioId, cueCombination, text, structuredSelection,
 *   freeText, timeTaken, realismFlag, realismNote
 * }
 *
 * @param {string} sessionId
 * @param {Array}  scenarios
 */
export async function updateScenarios(sessionId, scenarios) {
    await updateDoc(doc(db, SESSIONS, sessionId), { scenarios });
}

// ── Update — Stage 3: Policy Model ───────────────────────────────────

/**
 * Saves the fitted policy model after Screen 6.
 *
 * @param {string} sessionId
 * @param {{
 *   decisionTree: object,
 *   summaryText: string,
 *   expertAccuracyRating: 'accurate' | 'partial' | 'inaccurate',
 *   expertAccuracyNote: string,
 *   policyBreaks: string[]
 * }} policyModel
 */
export async function updatePolicyModel(sessionId, policyModel) {
    await updateDoc(doc(db, SESSIONS, sessionId), { policyModel });
}

// ── Update — Stage 4: Elicitation ────────────────────────────────────

/**
 * Saves the full elicitation transcript and triad result after Screen 7.
 *
 * @param {string} sessionId
 * @param {{
 *   cases: Array<{ scenarioId: string, exchange: Array<{ role: string, content: string }> }>,
 *   triad: { scenarioIds: string[], discriminationAnswer: string }
 * }} elicitation
 */
export async function updateElicitation(sessionId, elicitation) {
    await updateDoc(doc(db, SESSIONS, sessionId), { elicitation });
}

// ── Update — Stage 5: Recipe ──────────────────────────────────────────

/**
 * Saves the draft or confirmed Recipe after Screen 8.
 *
 * @param {string} sessionId
 * @param {{
 *   extractedKnowledge: string,
 *   trigger: string,
 *   actionSequence: string[],
 *   expectedOutcome: string,
 *   expertValidation: 'accurate' | 'needs-editing' | 'send-back',
 *   expertValidationNote: string,
 *   status: 'draft' | 'confirmed' | 'rejected'
 * }} recipe
 */
export async function updateRecipe(sessionId, recipe) {
    await updateDoc(doc(db, SESSIONS, sessionId), { recipe });
}

// ── Update — Stage 6: Transfer ────────────────────────────────────────

/**
 * Saves the learner transfer test data after Screen 9.
 *
 * @param {string} sessionId
 * @param {{
 *   learnerUid: string,
 *   preRecipeScenarios: Array<{ scenarioId: string, selection: string }>,
 *   postRecipeScenarios: Array<{ scenarioId: string, selection: string }>,
 *   comparisonResult: string,
 *   shiftMagnitude: number
 * }} transfer
 */
export async function updateTransfer(sessionId, transfer) {
    await updateDoc(doc(db, SESSIONS, sessionId), { transfer });
}